import{_ as a,o as d,c as e,ag as r}from"./chunks/framework.C6K0jwmI.js";const b=JSON.parse('{"title":"トラブルシューティング (総合)","description":"","frontmatter":{"feature_id":"TROUBLESHOOT","title":"トラブルシューティング (総合)","chapter":19,"plan":["all"],"role":["owner","manager","staff"],"audience":"全員","keywords":["トラブル","エラー","障害","サポート"],"related":["02-login","06-orders","07-kds","08-cashier","24-reservations"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"tenant/19-troubleshoot.md","filePath":"tenant/19-troubleshoot.md"}'),o={name:"tenant/19-troubleshoot.md"};function n(s,t,i,l,h,p){return d(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="_19-トラブルシューティング" tabindex="-1">19. トラブルシューティング <a class="header-anchor" href="#_19-トラブルシューティング" aria-label="Permalink to &quot;19. トラブルシューティング&quot;">​</a></h1><p>よくある問題と対処法をまとめています。</p><h2 id="_19-0-エラー番号の調べ方-2026-04-19-追加" tabindex="-1">19.0 エラー番号の調べ方（2026-04-19 追加） <a class="header-anchor" href="#_19-0-エラー番号の調べ方-2026-04-19-追加" aria-label="Permalink to &quot;19.0 エラー番号の調べ方（2026-04-19 追加）&quot;">​</a></h2><p>POSLA の全エラー（API レスポンス・画面表示）には <strong>E から始まる 4 桁の番号</strong>（E1xxx〜E9xxx）が振られています。何かが失敗したとき、画面には以下のような形式でエラーが表示されます。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[E3024] PIN が一致しません。再度入力してください。</span></span></code></pre></div><h3 id="_19-0-1-エラー番号を見たらまず何をするか" tabindex="-1">19.0.1 エラー番号を見たらまず何をするか <a class="header-anchor" href="#_19-0-1-エラー番号を見たらまず何をするか" aria-label="Permalink to &quot;19.0.1 エラー番号を見たらまず何をするか&quot;">​</a></h3><ol><li><strong>番号をそのまま控える</strong>（紙にメモ・スクショ・口頭でマネージャーに伝える）</li><li><strong>管理画面の右下にある オレンジ色 ? ボタン（AI ヘルプデスク FAB）</strong> を開く（<a href="./14-ai.html#146-ai-ヘルプデスク管理画面共通-fab">14.6</a> 参照）</li><li>質問欄に <code>[E3024]</code> と貼り付けて送信</li><li>AI がエラーカタログと該当章を照合して対処方法を返す</li></ol><p>エラー番号の意味と対処方法は <strong>章 99「エラーカタログ」</strong>（自動生成、<code>docs/manual/tenant/99-error-catalog.md</code>）に全件一覧化されています。AI ヘルプデスクが裏でこのカタログを参照しています。</p><h3 id="_19-0-2-エラー番号の桁の意味-参考" tabindex="-1">19.0.2 エラー番号の桁の意味（参考） <a class="header-anchor" href="#_19-0-2-エラー番号の桁の意味-参考" aria-label="Permalink to &quot;19.0.2 エラー番号の桁の意味（参考）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>範囲</th><th>系統</th></tr></thead><tbody><tr><td>E1xxx</td><td>認証・セッション系</td></tr><tr><td>E2xxx</td><td>入力バリデーション系</td></tr><tr><td>E3xxx</td><td>会計・PIN・決済系</td></tr><tr><td>E4xxx</td><td>注文・KDS 系</td></tr><tr><td>E5xxx</td><td>在庫・メニュー系</td></tr><tr><td>E6xxx</td><td>予約系</td></tr><tr><td>E7xxx</td><td>印刷・ハードウェア系</td></tr><tr><td>E8xxx</td><td>外部 API（Stripe / Gemini / Google）系</td></tr><tr><td>E9xxx</td><td>サーバー内部エラー（POSLA 運営対応案件）</td></tr></tbody></table><h3 id="_19-0-3-エラー番号がない古い画面に遭遇したら" tabindex="-1">19.0.3 エラー番号がない古い画面に遭遇したら <a class="header-anchor" href="#_19-0-3-エラー番号がない古い画面に遭遇したら" aria-label="Permalink to &quot;19.0.3 エラー番号がない古い画面に遭遇したら&quot;">​</a></h3><p><code>[Exxxx]</code> が付かないエラー（旧 UI からのレガシーメッセージ）は、エラーカタログ採番より前の実装か、JS 側のバリデーションです。動作には影響ありません。同じ症状で困った場合は文章そのものを AI ヘルプデスクに貼り付けてください。</p><hr><h2 id="_19-1-ログイン関連" tabindex="-1">19.1 ログイン関連 <a class="header-anchor" href="#_19-1-ログイン関連" aria-label="Permalink to &quot;19.1 ログイン関連&quot;">​</a></h2><h3 id="ログインできない" tabindex="-1">ログインできない <a class="header-anchor" href="#ログインできない" aria-label="Permalink to &quot;ログインできない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「ユーザー名またはパスワードが正しくありません」</td><td>入力ミス</td><td>大文字/小文字を確認。ユーザー名は全て小文字の場合が多い</td></tr><tr><td>「このアカウントは無効化されています」</td><td>アカウント無効化</td><td>オーナーまたはマネージャーに連絡してアカウントを有効化してもらう</td></tr><tr><td>「このテナントは無効化されています」</td><td>テナント自体が無効</td><td>POSLA運営に連絡</td></tr><tr><td>「通信エラーが発生しました」</td><td>インターネット未接続</td><td>Wi-Fi/モバイル通信を確認して再試行</td></tr><tr><td>「サーバーが空のレスポンスを返しました」</td><td>サーバー障害</td><td>しばらく待って再試行。繰り返す場合はPOSLA運営に連絡</td></tr></tbody></table><h3 id="セッションが頻繁に切れる" tabindex="-1">セッションが頻繁に切れる <a class="header-anchor" href="#セッションが頻繁に切れる" aria-label="Permalink to &quot;セッションが頻繁に切れる&quot;">​</a></h3><ul><li>25分間操作がないとタイムアウト警告が表示されます</li><li>30分で自動ログアウトされます</li><li>ブラウザのクッキーを削除した場合もログアウトされます</li><li>解決策：操作を継続するか、警告が出たら「操作を続ける」ボタンを押す</li></ul><h3 id="パスワード変更ができない" tabindex="-1">パスワード変更ができない <a class="header-anchor" href="#パスワード変更ができない" aria-label="Permalink to &quot;パスワード変更ができない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「パスワードは8文字以上で入力してください」</td><td>8文字未満</td><td>8文字以上のパスワードに変更</td></tr><tr><td>「パスワードには英字を1文字以上含めてください」</td><td>英字なし（数字だけ等）</td><td><code>tanaka123</code> のように英字を混ぜる</td></tr><tr><td>「パスワードには数字を1文字以上含めてください」</td><td>数字なし（英字だけ等）</td><td><code>tanaka123</code> のように数字を混ぜる</td></tr><tr><td>「現在のパスワードが正しくありません」</td><td>現在のパスワード入力ミス</td><td>現在のパスワードを確認。忘れた場合はオーナー / マネージャーにリセット依頼</td></tr><tr><td>「新しいパスワードと現在のパスワードが同じです」</td><td>同じパスワード</td><td>必ず別のパスワードに変更</td></tr><tr><td>パスワード変更後に他端末がログアウトされる</td><td>仕様（セキュリティ強化、P1-5）</td><td>他端末で再ログインすれば復帰可能</td></tr></tbody></table><h3 id="「aiサービスは現在利用できません」と表示される" tabindex="-1">「AIサービスは現在利用できません」と表示される <a class="header-anchor" href="#「aiサービスは現在利用できません」と表示される" aria-label="Permalink to &quot;「AIサービスは現在利用できません」と表示される&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>AIアシスタントタブで「AIサービスは現在利用できません。POSLA運営にお問い合わせください」</td><td>サーバー側でGemini APIキー未設定 / API障害</td><td>POSLA運営に連絡。テナント側で設定するキーはありません</td></tr></tbody></table><hr><h2 id="_19-2-注文関連" tabindex="-1">19.2 注文関連 <a class="header-anchor" href="#_19-2-注文関連" aria-label="Permalink to &quot;19.2 注文関連&quot;">​</a></h2><h3 id="セルフオーダーで注文できない" tabindex="-1">セルフオーダーで注文できない <a class="header-anchor" href="#セルフオーダーで注文できない" aria-label="Permalink to &quot;セルフオーダーで注文できない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「注文する」ボタンが無効</td><td>ラストオーダー中</td><td>マネージャーがラストオーダーを解除する（フロアマップの「LO解除」）</td></tr><tr><td>QRコードを読み取れない</td><td>QRコードが古い</td><td>管理ダッシュボードで新しいQRコードを生成・印刷</td></tr><tr><td>「品切れの品目が含まれています」</td><td>カート内品目が品切れ</td><td>該当品目をカートから削除して再送信</td></tr><tr><td>画面が真っ白</td><td>セッショントークン期限切れ</td><td>テーブルのセッショントークンが更新されている。新しいQRコードを使用</td></tr></tbody></table><h3 id="ハンディposで注文が送信されない" tabindex="-1">ハンディPOSで注文が送信されない <a class="header-anchor" href="#ハンディposで注文が送信されない" aria-label="Permalink to &quot;ハンディPOSで注文が送信されない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>「カートが空です」</td><td>カートに品目がない</td><td>メニューから品目を選択してカートに追加</td></tr><tr><td>「テーブルを選択してください」</td><td>テーブル未選択</td><td>ドロップダウンからテーブルを選択</td></tr><tr><td>通信エラー</td><td>ネットワーク問題</td><td>Wi-Fi接続を確認。安定した接続を確保</td></tr></tbody></table><hr><h2 id="_19-3-kds関連" tabindex="-1">19.3 KDS関連 <a class="header-anchor" href="#_19-3-kds関連" aria-label="Permalink to &quot;19.3 KDS関連&quot;">​</a></h2><h3 id="kdsに注文が表示されない" tabindex="-1">KDSに注文が表示されない <a class="header-anchor" href="#kdsに注文が表示されない" aria-label="Permalink to &quot;KDSに注文が表示されない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>全く注文が表示されない</td><td>ステーション選択の問題</td><td>「全品目」ボタンを選択して確認</td></tr><tr><td>一部の品目だけ表示されない</td><td>ステーションのカテゴリ割当</td><td>店舗設定でステーションの担当カテゴリを確認</td></tr><tr><td>更新が遅い</td><td>ポーリング</td><td>3秒間隔で自動更新されます。手動更新はありません</td></tr><tr><td>音が鳴らない</td><td>音声未許可</td><td>KDS起動時の「タップして開始」を確実に行う</td></tr></tbody></table><hr><h2 id="_19-4-会計・レジ関連" tabindex="-1">19.4 会計・レジ関連 <a class="header-anchor" href="#_19-4-会計・レジ関連" aria-label="Permalink to &quot;19.4 会計・レジ関連&quot;">​</a></h2><h3 id="レジで会計できない" tabindex="-1">レジで会計できない <a class="header-anchor" href="#レジで会計できない" aria-label="Permalink to &quot;レジで会計できない&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>会計待ちテーブルが表示されない</td><td>未会計の注文がない</td><td>注文が入っているか確認</td></tr><tr><td>「会計する」ボタンが押せない</td><td>処理中</td><td>二重押し防止。しばらく待つ</td></tr><tr><td>カードリーダーが接続できない</td><td>Stripe Terminal問題</td><td>「再検出」ボタンで再接続。端末の電源を確認</td></tr></tbody></table><h3 id="pin-を求められる操作の一覧-cb1d、2026-04-19-更新" tabindex="-1">PIN を求められる操作の一覧（CB1d、2026-04-19 更新） <a class="header-anchor" href="#pin-を求められる操作の一覧-cb1d、2026-04-19-更新" aria-label="Permalink to &quot;PIN を求められる操作の一覧（CB1d、2026-04-19 更新）&quot;">​</a></h3><p>会計・返金・<strong>レジ金庫操作（開け / 閉め / 入金 / 出金）</strong> の全てで担当スタッフ PIN が必須です。マネージャー/オーナーも例外なし。</p><table tabindex="0"><thead><tr><th>操作</th><th>PIN 必須</th></tr></thead><tbody><tr><td>会計確定（現金 / カード / QR / Terminal）</td><td>✅</td></tr><tr><td>返金処理</td><td>✅</td></tr><tr><td><strong>レジ開け / レジ閉め / 入金 / 出金</strong>（CB1d 新規）</td><td>✅</td></tr></tbody></table><p>「PIN が一致しないか、対象スタッフが出勤中ではありません」エラーが出る場合は: ① 自分の出勤打刻を確認 / ② PIN 設定済みか確認 / ③ 入力ミスがないか確認、の順で対処してください。</p><h3 id="レジの過不足が大きい" tabindex="-1">レジの過不足が大きい <a class="header-anchor" href="#レジの過不足が大きい" aria-label="Permalink to &quot;レジの過不足が大きい&quot;">​</a></h3><ul><li>レジレポートでキャッシュログを確認し、入金・出金の記録漏れがないか確認</li><li>出金を記録せずに現金を取り出していないか確認（CB1d 以降は出金にも PIN 必須なので、PIN なし出金は物理的に不可能）</li><li>閾値（デフォルト¥500）を超える過不足は自動で警告表示されます</li><li>CB1d 以降、レジ開け/閉め/入金/出金には誰が操作したかが <code>audit_log</code> に記録されているので、差額調査時に「いつ・誰が・何のために動かしたか」を追跡できます</li></ul><hr><h2 id="_19-5-ネットワーク関連" tabindex="-1">19.5 ネットワーク関連 <a class="header-anchor" href="#_19-5-ネットワーク関連" aria-label="Permalink to &quot;19.5 ネットワーク関連&quot;">​</a></h2><h3 id="オフライン警告が表示される" tabindex="-1">オフライン警告が表示される <a class="header-anchor" href="#オフライン警告が表示される" aria-label="Permalink to &quot;オフライン警告が表示される&quot;">​</a></h3><p>POSLAはクラウド型システムのため、常時インターネット接続が必要です。</p><ul><li>画面上部に赤いバナーで「オフライン」警告が表示されます</li><li>オフライン中は新規注文の送信やデータ取得ができません</li><li>接続が復旧すると自動的に緑のバナーが表示され、通常動作に戻ります</li></ul><p><strong>対処法：</strong></p><ol><li>Wi-Fiルーターの状態を確認</li><li>モバイル通信に切り替えて試す</li><li>有線LAN接続を検討（安定性向上）</li><li>バックアップ用のモバイルルーターを準備</li></ol><h3 id="セルフオーダーの注文がオフライン時に保留される" tabindex="-1">セルフオーダーの注文がオフライン時に保留される <a class="header-anchor" href="#セルフオーダーの注文がオフライン時に保留される" aria-label="Permalink to &quot;セルフオーダーの注文がオフライン時に保留される&quot;">​</a></h3><p>お客さんのスマートフォンがオフラインの場合、注文はブラウザに保留されます。接続が復旧すると自動的に送信されます。24時間以上経過した保留注文は自動破棄されます。</p><hr><h2 id="_19-6-メニュー関連" tabindex="-1">19.6 メニュー関連 <a class="header-anchor" href="#_19-6-メニュー関連" aria-label="Permalink to &quot;19.6 メニュー関連&quot;">​</a></h2><h3 id="メニュー変更が反映されない" tabindex="-1">メニュー変更が反映されない <a class="header-anchor" href="#メニュー変更が反映されない" aria-label="Permalink to &quot;メニュー変更が反映されない&quot;">​</a></h3><p>管理ダッシュボードでメニューを変更した後、各画面への反映タイミングは以下のとおりです。</p><table tabindex="0"><thead><tr><th>画面</th><th>反映タイミング</th></tr></thead><tbody><tr><td>セルフオーダー</td><td>メニューバージョンチェック（3分間隔）またはページリロード</td></tr><tr><td>ハンディPOS</td><td>メニューバージョンチェック（3分間隔）</td></tr><tr><td>KDS</td><td>次の注文受信時</td></tr></tbody></table><p>急ぎの場合は、各画面でブラウザをリロード（F5）してください。</p><hr><h2 id="_19-7-シフト関連" tabindex="-1">19.7 シフト関連 <a class="header-anchor" href="#_19-7-シフト関連" aria-label="Permalink to &quot;19.7 シフト関連&quot;">​</a></h2><h3 id="gps打刻でエラーが出る" tabindex="-1">GPS打刻でエラーが出る <a class="header-anchor" href="#gps打刻でエラーが出る" aria-label="Permalink to &quot;GPS打刻でエラーが出る&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処法</th></tr></thead><tbody><tr><td>位置情報の許可エラー</td><td>ブラウザの位置情報が無効</td><td>ブラウザの設定で位置情報を許可する</td></tr><tr><td>距離エラー</td><td>店舗から離れすぎている</td><td>店舗の許容半径内（シフト設定で確認）に移動してから打刻</td></tr><tr><td>「既に出勤中です」</td><td>二重打刻</td><td>前回の退勤打刻ができていない。マネージャーに確認</td></tr></tbody></table><hr><h2 id="_19-8-推奨環境の確認" tabindex="-1">19.8 推奨環境の確認 <a class="header-anchor" href="#_19-8-推奨環境の確認" aria-label="Permalink to &quot;19.8 推奨環境の確認&quot;">​</a></h2><p>問題が解決しない場合、以下の環境を確認してください。</p><table tabindex="0"><thead><tr><th>項目</th><th>推奨</th></tr></thead><tbody><tr><td>ブラウザ</td><td>Google Chrome（最新版）推奨</td></tr><tr><td>管理ダッシュボード</td><td>PC/タブレット（10インチ以上）</td></tr><tr><td>KDS</td><td>タブレット（10インチ以上、横置き）</td></tr><tr><td>ハンディPOS</td><td>スマートフォン（5〜8インチ）</td></tr><tr><td>インターネット</td><td>安定した接続（Wi-Fi推奨、有線LANがベスト）</td></tr></tbody></table><hr><h2 id="_19-9-posla運営への問い合わせ" tabindex="-1">19.9 POSLA運営への問い合わせ <a class="header-anchor" href="#_19-9-posla運営への問い合わせ" aria-label="Permalink to &quot;19.9 POSLA運営への問い合わせ&quot;">​</a></h2><p>上記で解決しない場合は、POSLA運営（プラスビリーフ）にお問い合わせください。</p><p>問い合わせ時に以下の情報をお伝えいただくと、迅速な対応が可能です。</p><ul><li>テナント名・店舗名</li><li>問題が発生した日時</li><li>問題の症状（エラーメッセージがあれば正確に）</li><li>使用しているブラウザとOS</li><li>問題が発生する画面（管理ダッシュボード/KDS/ハンディPOS/セルフオーダー等）</li></ul><hr><h2 id="_19-x-新機能のトラブル参照" tabindex="-1">19.X 新機能のトラブル参照 <a class="header-anchor" href="#_19-x-新機能のトラブル参照" aria-label="Permalink to &quot;19.X 新機能のトラブル参照&quot;">​</a></h2><p>各機能の詳細トラブルは該当章を参照:</p><ul><li>予約関連: <a href="./24-reservations.html">24 章 24.17</a></li><li>テーブル開放関連: <a href="./25-table-auth.html">25 章 25.11</a></li><li>プリンタ関連: <a href="./26-printer.html">26 章 26.11</a></li><li>注文関連: <a href="./06-orders.html">6 章 6.15</a></li><li>KDS: <a href="./07-kds.html">7 章 7.13</a></li><li>レジ: <a href="./08-cashier.html">8 章 8.15</a></li></ul><hr><h2 id="_19-10-緊急対応フロー-重大障害時" tabindex="-1">19.10 緊急対応フロー（重大障害時） <a class="header-anchor" href="#_19-10-緊急対応フロー-重大障害時" aria-label="Permalink to &quot;19.10 緊急対応フロー（重大障害時）&quot;">​</a></h2><h3 id="_19-10-1-すぐ確認すべき-5-つの項目" tabindex="-1">19.10.1 すぐ確認すべき 5 つの項目 <a class="header-anchor" href="#_19-10-1-すぐ確認すべき-5-つの項目" aria-label="Permalink to &quot;19.10.1 すぐ確認すべき 5 つの項目&quot;">​</a></h3><ol><li><strong>POSLA は動いている？</strong> — <code>https://eat.posla.jp/api/monitor/ping.php</code> を Chrome で開く → <code>{&quot;ok&quot;:true}</code> が返れば OK</li><li><strong>店内 Wi-Fi は生きている？</strong> — タブレットの Wi-Fi マークが扇形 3 本表示されているか</li><li><strong>インターネットに繋がってる？</strong> — Chrome で <code>https://google.com</code> を開いて表示されるか</li><li><strong>電源は来てる？</strong> — タブレット・ルーター・プリンタ・カードリーダーの電源ランプ確認</li><li><strong>特定の端末だけ？</strong> — 別の端末で同じ操作を試してみる</li></ol><h3 id="_19-10-2-障害判別フローチャート" tabindex="-1">19.10.2 障害判別フローチャート <a class="header-anchor" href="#_19-10-2-障害判別フローチャート" aria-label="Permalink to &quot;19.10.2 障害判別フローチャート&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 端末だけ動かない</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>   端末再起動 → 改善？</span></span>
<span class="line"><span>    ↓ NO</span></span>
<span class="line"><span>   ブラウザリロード（Cmd+Shift+R） → 改善？</span></span>
<span class="line"><span>    ↓ NO</span></span>
<span class="line"><span>   別ブラウザ・別端末で同じ操作 → 動く?</span></span>
<span class="line"><span>    ↓ YES</span></span>
<span class="line"><span>   元端末の問題 → 端末交換 or サポート連絡</span></span>
<span class="line"><span></span></span>
<span class="line"><span>全端末動かない</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>   POSLA 全体障害の可能性 → POSLA 運営に連絡</span></span>
<span class="line"><span>   または、店舗 Wi-Fi 障害の可能性 → ルーター再起動</span></span></code></pre></div><h3 id="_19-10-3-営業継続のためのバックアップ手順" tabindex="-1">19.10.3 営業継続のためのバックアップ手順 <a class="header-anchor" href="#_19-10-3-営業継続のためのバックアップ手順" aria-label="Permalink to &quot;19.10.3 営業継続のためのバックアップ手順&quot;">​</a></h3><p>POSLA が完全に止まった場合の <strong>営業継続手順</strong>:</p><ol><li><strong>手書き伝票</strong> で注文を取る</li><li><strong>電卓</strong> で会計</li><li><strong>現金</strong> メインで対応（カード決済は不可）</li><li>レシートは手書き or 後日発行</li><li>復旧後、<strong>手書き伝票を POSLA に手動入力</strong>（売上記録のため）</li></ol><div class="tip custom-block"><p class="custom-block-title">手書き伝票テンプレートを準備</p><p>営業中の障害に備えて、手書き伝票（カーボン紙）を最低 50 枚は店舗に常備してください。</p></div><hr><h2 id="_19-11-ブラウザ別の既知の問題" tabindex="-1">19.11 ブラウザ別の既知の問題 <a class="header-anchor" href="#_19-11-ブラウザ別の既知の問題" aria-label="Permalink to &quot;19.11 ブラウザ別の既知の問題&quot;">​</a></h2><h3 id="_19-11-1-ios-safari" tabindex="-1">19.11.1 iOS Safari <a class="header-anchor" href="#_19-11-1-ios-safari" aria-label="Permalink to &quot;19.11.1 iOS Safari&quot;">​</a></h3><ul><li><strong>Web Speech API（音声認識）の continuous モード非対応</strong> → KDS 音声コマンドは Chrome 必須</li><li><strong>PWA キャッシュが強い</strong> → Cmd+Shift+R では足りず、設定からキャッシュクリアが必要</li></ul><h3 id="_19-11-2-android-chrome" tabindex="-1">19.11.2 Android Chrome <a class="header-anchor" href="#_19-11-2-android-chrome" aria-label="Permalink to &quot;19.11.2 Android Chrome&quot;">​</a></h3><ul><li><strong>位置情報精度が機種により大きく異なる</strong> → GPS 半径を 300m 以上に設定</li><li><strong>古い Android (8 以下) はサポート対象外</strong></li></ul><h3 id="_19-11-3-windows-edge" tabindex="-1">19.11.3 Windows Edge <a class="header-anchor" href="#_19-11-3-windows-edge" aria-label="Permalink to &quot;19.11.3 Windows Edge&quot;">​</a></h3><ul><li><strong>基本動作は OK</strong></li><li><strong>キーボードショートカット F1-F3</strong> が標準ヘルプを開いてしまう → 設定で無効化</li></ul><h3 id="_19-11-4-mac-safari" tabindex="-1">19.11.4 Mac Safari <a class="header-anchor" href="#_19-11-4-mac-safari" aria-label="Permalink to &quot;19.11.4 Mac Safari&quot;">​</a></h3><ul><li><strong>基本動作は OK</strong></li><li><strong>ダウンロード時にファイル名が文字化け</strong> → Chrome 推奨</li></ul><hr><h2 id="_19-12-アクセス権限関連のトラブル" tabindex="-1">19.12 アクセス権限関連のトラブル <a class="header-anchor" href="#_19-12-アクセス権限関連のトラブル" aria-label="Permalink to &quot;19.12 アクセス権限関連のトラブル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>「権限が不足しています」</td><td>ロール（staff/manager/owner）不足</td><td>上司に依頼</td></tr><tr><td>タブが表示されない</td><td>ロール制御で非表示</td><td>仕様。3 章ロール表参照</td></tr><tr><td>owner-dashboard が見えない</td><td>staff or manager で開いた</td><td>owner アカウントでログイン必要</td></tr><tr><td>在庫タブが owner で見えない</td><td>仕様（manager 専用）</td><td>manager でログイン</td></tr><tr><td>他店舗のデータが見えない</td><td>テナント境界</td><td>owner で店舗切替が必要</td></tr></tbody></table><hr><h2 id="_19-y-緊急時のサポート連絡先" tabindex="-1">19.Y 緊急時のサポート連絡先 <a class="header-anchor" href="#_19-y-緊急時のサポート連絡先" aria-label="Permalink to &quot;19.Y 緊急時のサポート連絡先&quot;">​</a></h2><table tabindex="0"><thead><tr><th>連絡先</th><th>内容</th><th>対応時間</th></tr></thead><tbody><tr><td><code>info@posla.jp</code></td><td>POSLA 全般の問い合わせ</td><td>24 時間以内回答（営業時間外は BD 朝対応）</td></tr><tr><td>Stripe Dashboard</td><td>決済関連トラブル</td><td>Stripe サポート（メール / チャット）</td></tr><tr><td>スマレジサポート</td><td>スマレジ連携トラブル</td><td>スマレジ社の窓口</td></tr><tr><td>インターネット契約先</td><td>回線トラブル</td><td>NTT / ソフトバンク等のサポート</td></tr></tbody></table><p><strong>重大障害時は POSLA 運営側で自動検知 (I-1)</strong> され、Slack + メールでアラートが発火します（5 分以内）。お客様から連絡なくても POSLA 運営が気づける仕組み。</p><h2 id="_19-13-トラブル切り分けの基本フローチャート" tabindex="-1">19.13 トラブル切り分けの基本フローチャート <a class="header-anchor" href="#_19-13-トラブル切り分けの基本フローチャート" aria-label="Permalink to &quot;19.13 トラブル切り分けの基本フローチャート&quot;">​</a></h2><p>POSLA で「動かない」と言われたとき、まずこのフローを上から順に確認してください。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[症状報告]</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Step 1: スコープ判定 ───────────────────────</span></span>
<span class="line"><span>    │   この症状は…</span></span>
<span class="line"><span>    │   ① 1 端末だけ?         → Step 2 へ (端末問題)</span></span>
<span class="line"><span>    │   ② 1 店舗の全端末?      → Step 3 へ (Wi-Fi/設定)</span></span>
<span class="line"><span>    │   ③ 全店舗 / 全テナント? → Step 4 へ (POSLA 障害)</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Step 2: 単一端末問題</span></span>
<span class="line"><span>    │   ┌─ ブラウザリロード (Cmd+Shift+R) → 直る? → 終了</span></span>
<span class="line"><span>    │   ├─ 別ブラウザで同じ操作 → 動く? → 元ブラウザのキャッシュクリア</span></span>
<span class="line"><span>    │   ├─ 別端末で同じ操作 → 動く? → 元端末を再起動 / 交換</span></span>
<span class="line"><span>    │   └─ 全部 NG → POSLA 運営連絡</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    ├─ Step 3: 店舗単位問題</span></span>
<span class="line"><span>    │   ┌─ ルーター再起動 (電源 30 秒オフ) → 直る? → 終了</span></span>
<span class="line"><span>    │   ├─ https://google.com 開ける? → No なら回線会社へ</span></span>
<span class="line"><span>    │   ├─ POSLA 設定が誤っていないか (タイムアウト/権限) → 修正</span></span>
<span class="line"><span>    │   └─ 全部 NG → POSLA 運営連絡</span></span>
<span class="line"><span>    │</span></span>
<span class="line"><span>    └─ Step 4: 全体障害の可能性</span></span>
<span class="line"><span>        ┌─ https://eat.posla.jp/api/monitor/ping.php</span></span>
<span class="line"><span>        │   → {&quot;ok&quot;:true} 返る? → No なら POSLA 全停止 (運営に連絡)</span></span>
<span class="line"><span>        └─ POSLA 運営の Slack/メール通知を確認</span></span>
<span class="line"><span>            → 通知あり → 復旧待ち</span></span>
<span class="line"><span>            → 通知なし → POSLA 運営に第一報</span></span></code></pre></div><h2 id="_19-14-ブラウザ・キャッシュ・セッション・gps・wi-fi-の切り分け" tabindex="-1">19.14 ブラウザ・キャッシュ・セッション・GPS・Wi-Fi の切り分け <a class="header-anchor" href="#_19-14-ブラウザ・キャッシュ・セッション・gps・wi-fi-の切り分け" aria-label="Permalink to &quot;19.14 ブラウザ・キャッシュ・セッション・GPS・Wi-Fi の切り分け&quot;">​</a></h2><p>「ログイン後すぐ画面が真っ白」「ボタンを押しても何も起きない」など、現象が漠然としているときは以下 5 点を順に切り分けます。</p><h3 id="_19-14-1-ブラウザキャッシュ" tabindex="-1">19.14.1 ブラウザキャッシュ <a class="header-anchor" href="#_19-14-1-ブラウザキャッシュ" aria-label="Permalink to &quot;19.14.1 ブラウザキャッシュ&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>確認方法</th><th>対処</th></tr></thead><tbody><tr><td>古い UI が表示される</td><td>DevTools → Network → JS の Status: <code>200 (from disk cache)</code></td><td>Cmd+Shift+R で強制リロード</td></tr><tr><td>キャッシュバスター (<code>?v=xxx</code>) を更新しても古い</td><td>同上</td><td>DevTools → Application → Storage → Clear site data</td></tr><tr><td>iOS Safari でしつこいキャッシュ</td><td>キャッシュバスターも効かない</td><td>設定アプリ → Safari → 履歴と Web サイトデータを消去</td></tr></tbody></table><h3 id="_19-14-2-セッション" tabindex="-1">19.14.2 セッション <a class="header-anchor" href="#_19-14-2-セッション" aria-label="Permalink to &quot;19.14.2 セッション&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>確認方法</th><th>対処</th></tr></thead><tbody><tr><td>操作ごとに「ログインしてください」</td><td>DevTools → Application → Cookies で <code>PHPSESSID</code> 確認</td><td>Cookie ブロック解除 / サードパーティ Cookie 許可</td></tr><tr><td>25 分でログアウト警告</td><td>仕様 (CLAUDE.md セッション TTL)</td><td>操作継続 or 「操作を続ける」クリック</td></tr><tr><td>別端末でログインしたら旧端末が落ちた</td><td>パスワード変更直後</td><td>旧端末で再ログイン (P1-5 仕様)</td></tr></tbody></table><h3 id="_19-14-3-gps" tabindex="-1">19.14.3 GPS <a class="header-anchor" href="#_19-14-3-gps" aria-label="Permalink to &quot;19.14.3 GPS&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>確認方法</th><th>対処</th></tr></thead><tbody><tr><td>「位置情報の取得に失敗しました」</td><td>ブラウザ設定 → 位置情報 → eat.posla.jp 許可</td><td>許可に変更</td></tr><tr><td>「店舗から離れすぎています」</td><td>16 章で店舗 GPS 半径 (デフォルト 200m) を確認</td><td>半径を 300-500m に拡大 / 店舗位置を再設定</td></tr><tr><td>屋内で GPS が取れない</td><td>商業ビル地下 / 鉄筋ビル中央</td><td>Wi-Fi 位置情報を ON / 半径を 500m 以上</td></tr><tr><td>device で GPS 強制が効かない</td><td><code>gps_required</code> カラム値</td><td>device は常に強制 (kds-auth.js 参照)</td></tr></tbody></table><h3 id="_19-14-4-wi-fi-ネットワーク" tabindex="-1">19.14.4 Wi-Fi / ネットワーク <a class="header-anchor" href="#_19-14-4-wi-fi-ネットワーク" aria-label="Permalink to &quot;19.14.4 Wi-Fi / ネットワーク&quot;">​</a></h3><table tabindex="0"><thead><tr><th>症状</th><th>確認方法</th><th>対処</th></tr></thead><tbody><tr><td>注文が送信できない</td><td>画面上部の赤い「オフライン」バナー</td><td>Wi-Fi 再接続 / モバイルに切替</td></tr><tr><td>速度が遅い (ローディング 5 秒以上)</td><td><a href="https://fast.com" target="_blank" rel="noreferrer">https://fast.com</a> で実測</td><td>5Mbps 以上が目安。下回るなら回線増強</td></tr><tr><td>同時接続超過</td><td>ルーター管理画面で接続数</td><td>業務用ルーターに交換 (50 台以上想定)</td></tr><tr><td>カードリーダーが応答しない</td><td>Stripe Reader S700 と同 LAN か</td><td>レジ端末とリーダーを同 SSID に</td></tr></tbody></table><h3 id="_19-14-5-ブラウザ-devtools-の使い方-基本" tabindex="-1">19.14.5 ブラウザ DevTools の使い方（基本） <a class="header-anchor" href="#_19-14-5-ブラウザ-devtools-の使い方-基本" aria-label="Permalink to &quot;19.14.5 ブラウザ DevTools の使い方（基本）&quot;">​</a></h3><ol><li>Chrome で問題画面を開く</li><li><strong>F12</strong> または <strong>Cmd+Option+I</strong> で DevTools を開く</li><li>上部タブから: <ul><li><strong>Console</strong>: JS エラー (赤字) を確認</li><li><strong>Network</strong>: API レスポンス (<code>/api/...</code>) のステータス確認</li><li><strong>Application</strong> → Storage: Cookie / localStorage / Cache 確認</li></ul></li><li>POSLA 運営に問い合わせる時は <strong>Console のスクリーンショット</strong> を添付すると 5 倍速く解決する</li></ol><h2 id="_19-15-操作前チェックリスト-トラブル発生時" tabindex="-1">19.15 操作前チェックリスト（トラブル発生時） <a class="header-anchor" href="#_19-15-操作前チェックリスト-トラブル発生時" aria-label="Permalink to &quot;19.15 操作前チェックリスト（トラブル発生時）&quot;">​</a></h2><p>「動かない」と気づいたら、まず以下を 30 秒で確認してください。</p><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th><th style="text-align:center;">OK / NG</th></tr></thead><tbody><tr><td>1</td><td>エラー番号 <code>[Exxxx]</code> が画面に出ている?</td><td style="text-align:center;">□</td></tr><tr><td>2</td><td>エラー文の正確な日本語をメモした?</td><td style="text-align:center;">□</td></tr><tr><td>3</td><td>自分のロール (owner/manager/staff/device) を把握した?</td><td style="text-align:center;">□</td></tr><tr><td>4</td><td>自分が操作した手順を順に書き出した?</td><td style="text-align:center;">□</td></tr><tr><td>5</td><td>ブラウザ・端末・店舗名・時刻を控えた?</td><td style="text-align:center;">□</td></tr><tr><td>6</td><td>同じ操作を別端末で試した?</td><td style="text-align:center;">□</td></tr><tr><td>7</td><td>Wi-Fi の状態 (扇形マーク) を確認した?</td><td style="text-align:center;">□</td></tr><tr><td>8</td><td>DevTools Console のエラーを見た? (任意)</td><td style="text-align:center;">□</td></tr></tbody></table><p>このチェックを済ませてから <strong>AI ヘルプデスク FAB</strong> または POSLA 運営に問い合わせると、解決速度が劇的に上がります。</p><h2 id="_19-16-実例ベースのトラブル対応-matsunoya-torimaru" tabindex="-1">19.16 実例ベースのトラブル対応（matsunoya / torimaru） <a class="header-anchor" href="#_19-16-実例ベースのトラブル対応-matsunoya-torimaru" aria-label="Permalink to &quot;19.16 実例ベースのトラブル対応（matsunoya / torimaru）&quot;">​</a></h2><h3 id="_19-16-1-matsunoya-渋谷店-ピーク時に-kds-が固まった" tabindex="-1">19.16.1 matsunoya 渋谷店: ピーク時に KDS が固まった <a class="header-anchor" href="#_19-16-1-matsunoya-渋谷店-ピーク時に-kds-が固まった" aria-label="Permalink to &quot;19.16.1 matsunoya 渋谷店: ピーク時に KDS が固まった&quot;">​</a></h3><p><strong>症状</strong>: 19:00 のピーク時、KDS 画面の更新が止まり、新規注文が表示されなくなった。</p><p><strong>切り分け</strong>:</p><ol><li>✅ 1 店舗のみ → Step 3 (Wi-Fi/設定) へ</li><li>✅ ルーター再起動 → 改善せず</li><li>✅ <code>https://google.com</code> は開ける → 回線は生きている</li><li>✅ 別タブで <code>eat.posla.jp/api/monitor/ping.php</code> → <code>{&quot;ok&quot;:true}</code> → POSLA は生きている</li><li>✅ DevTools Console → <code>Failed to fetch /api/kds/orders.php</code> が連発 → サーバー側の負荷</li><li>→ POSLA 運営に連絡 → 5 分後復旧 (DB 接続プール枯渇が原因)</li></ol><p><strong>学び</strong>: ピーク時のフリーズは個別店舗側で解決しないことが多い。POSLA 運営が監視 (I-1) で気づくが、報告ありの方が早い。</p><h3 id="_19-16-2-torimaru-パスワードを忘れて全員入れない" tabindex="-1">19.16.2 torimaru: パスワードを忘れて全員入れない <a class="header-anchor" href="#_19-16-2-torimaru-パスワードを忘れて全員入れない" aria-label="Permalink to &quot;19.16.2 torimaru: パスワードを忘れて全員入れない&quot;">​</a></h3><p><strong>症状</strong>: 個人店、オーナーが旅行中に唯一のスタッフがパスワードを忘れた。</p><p><strong>切り分け</strong>:</p><ol><li>✅ ロール: staff → manager / owner にリセット依頼が必要</li><li>✅ owner と LINE 通話 → owner のスマホからログイン → スタッフのパスワードリセット</li><li>✅ 仮パスワードをスタッフに口頭で伝える → スタッフ自身が変更</li></ol><p><strong>学び</strong>: owner の連絡先は店舗内に必ず控えておく。1 オーナー店舗は特にリスクが高い。</p><h2 id="_19-17-よくある質問-faq" tabindex="-1">19.17 よくある質問 (FAQ) <a class="header-anchor" href="#_19-17-よくある質問-faq" aria-label="Permalink to &quot;19.17 よくある質問 (FAQ)&quot;">​</a></h2><p><strong>Q1. 「動かない」と思ったら最初に何をすべき?</strong></p><p>A. ブラウザリロード (Cmd+Shift+R)。次にエラー番号をメモして AI ヘルプデスク FAB に貼り付ける。</p><p><strong>Q2. POSLA 運営の電話番号は?</strong></p><p>A. 電話窓口は提供していません。<code>info@posla.jp</code> メール、または POSLA 内蔵の「お問い合わせ」フォームを使ってください。</p><p><strong>Q3. POSLA が完全に止まったら売上はどうなる?</strong></p><p>A. 19.10.3 のバックアップ手順で手書き伝票運用 → 復旧後手動入力。手書き伝票は最低 50 枚常備推奨。</p><p><strong>Q4. AI ヘルプデスクの回答が間違っていることがある</strong></p><p>A. AI は確率的なので 100% 正確ではありません。重要な操作は本マニュアルの該当章を必ず確認してください。</p><p><strong>Q5. エラー番号が <code>[Exxxx]</code> 形式じゃない場合は?</strong></p><p>A. レガシーメッセージです。文章そのままを AI ヘルプデスクに貼り付けるか、19.X の各章別トラブル参照へ。</p><p><strong>Q6. 「権限が不足しています」が頻発する</strong></p><p>A. ロール (staff/manager/owner) と所属店舗を確認。3 章 3.18 のロール別タブ可視性表を参照。</p><p><strong>Q7. デバイス端末 (KDS / レジ / ハンディ) でトラブル</strong></p><p>A. device アカウントは特殊です。23 章 (KDS デバイス端末ガイド) と 2 章 2.5 (デバイス管理) を参照。</p><p><strong>Q8. レポートの数字が他と合わない</strong></p><p>A. 集計タイミングの差です。13 章「レポート」の集計仕様を参照。日次集計は翌日朝に確定。</p><p><strong>Q9. プリンタが印刷されない</strong></p><p>A. 26 章「プリンタ連携」の 26.11 を参照。IP プリンタ専用なので USB / Bluetooth は対象外。</p><p><strong>Q10. Stripe / スマレジ連携で詰まった</strong></p><p>A. 21 章 (Stripe) / 22 章 (スマレジ、internal) のトラブル節を参照。決済関連は POSLA 運営でも事象再現が難しいので、エラー番号 + Stripe Dashboard のスクショ必須。</p><p><strong>Q11. メニュー編集が反映されない</strong></p><p>A. 19.6 参照。3 分のメニューバージョンチェック後反映。急ぎはブラウザリロード。</p><p><strong>Q12. 予約・テーブル開放のトラブル</strong></p><p>A. 24 章 (予約) / 25 章 (テーブル開放認証) のトラブル節を参照。</p><p><strong>Q13. PIN を求められる操作で何度も弾かれる</strong></p><p>A. CB1d 仕様: ① 自分の出勤打刻を確認 / ② PIN 設定済みか確認 / ③ 入力ミス。3 回連続失敗で 10 分ロック。</p><p><strong>Q14. iOS Safari で音声コマンドが動かない</strong></p><p>A. 仕様 (Web Speech API continuous モード非対応)。Chrome を使ってください。</p><p><strong>Q15. Android 古機種で位置情報が取れない</strong></p><p>A. Android 8 以下は非対応。新しい端末に交換してください。</p><h2 id="_19-s3-s3-セキュリティ修正で追加された新エラーコード-2026-04-19" tabindex="-1">19.S3 S3 セキュリティ修正で追加された新エラーコード（2026-04-19） <a class="header-anchor" href="#_19-s3-s3-セキュリティ修正で追加された新エラーコード-2026-04-19" aria-label="Permalink to &quot;19.S3 S3 セキュリティ修正で追加された新エラーコード（2026-04-19）&quot;">​</a></h2><p>S3 セキュリティ修正一式で新規追加されたエラー文字列です。E 番号は次回 catalog 再生成で採番されます。詳細は <a href="./18-security.html#18w-s3-セキュリティ修正一式2026-04-19">18.W S3 セキュリティ修正一式</a> を参照。</p><table tabindex="0"><thead><tr><th>エラー文字列</th><th>HTTP</th><th>発生 API</th><th>意味と対処</th></tr></thead><tbody><tr><td><code>INVALID_ITEM</code></td><td>400</td><td>handy-order, takeout-orders</td><td>注文に存在しないメニュー ID が含まれる → 端末再読込で最新メニューを取得</td></tr><tr><td><code>INVALID_OPTION</code></td><td>400</td><td>handy-order, takeout-orders</td><td>注文に存在しないオプション ID が含まれる → 端末再読込</td></tr><tr><td><code>INVALID_QUANTITY</code></td><td>400</td><td>handy-order, takeout-orders</td><td>数量が 0 / 負数 / 上限超過 → 数量を確認して再送信</td></tr><tr><td><code>ALREADY_PAID</code></td><td>409</td><td>process-payment, checkout-confirm</td><td>別スタッフが先に会計済み → 画面リロードで最新状態確認。<strong>重複課金は発生していない</strong></td></tr><tr><td><code>AMOUNT_MISMATCH</code></td><td>409</td><td>process-payment, handy-order</td><td>クライアント表示金額とサーバー再計算金額が不一致 → 端末再読込で最新価格取得</td></tr><tr><td><code>STRIPE_MISMATCH</code></td><td>409</td><td>process-payment</td><td>Stripe Terminal の retrieve 結果が DB の payment_intent と不一致 → POSLA 運営に連絡</td></tr><tr><td><code>PAYMENT_NOT_CONFIRMED</code></td><td>402</td><td>signup/activate</td><td>Stripe Subscription が active/trialing でない → カード登録を完了してから再試行</td></tr><tr><td><code>INVALID_TOKEN</code></td><td>404</td><td>signup/activate</td><td>signup_token が DB に存在しない → メール本文の URL を再確認</td></tr><tr><td><code>CONFLICT</code></td><td>409</td><td>process-payment, reservation-create, checkout-confirm</td><td>レースコンディション検出 → 画面リロード後に再操作</td></tr><tr><td><code>CAPACITY_EXCEEDED</code></td><td>409</td><td>takeout-orders</td><td>テイクアウト時間枠の容量を超過 → 別の時間枠を選択</td></tr><tr><td><code>WEBHOOK_NOT_CONFIGURED</code></td><td>503</td><td>signup/webhook</td><td><code>stripe_webhook_secret</code> が POSLA 運営側で未設定 → 運営に連絡</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">CONFLICT / ALREADY_PAID が出たら</p><p><strong>焦らず画面をリロード</strong>してください。多くの場合、別のスタッフ（あるいは別の端末）が同じ操作を一足先に完了しています。サーバー側の排他制御が正しく機能している証拠なので、データ破損は発生していません。</p></div><hr><h2 id="_19-18-関連章" tabindex="-1">19.18 関連章 <a class="header-anchor" href="#_19-18-関連章" aria-label="Permalink to &quot;19.18 関連章&quot;">​</a></h2><ul><li><a href="./99-error-catalog.html">99 章 エラーカタログ</a> — 全 E 番号の意味と対処</li><li><a href="./03-dashboard.html">3 章 管理ダッシュボード</a> — タブ別の挙動</li><li><a href="./14-ai.html">14 章 AI アシスタント</a> — AI ヘルプデスク FAB の詳細</li><li><a href="./21-stripe-full.html">21 章 Stripe</a> — 決済関連トラブル</li><li><a href="./23-kds-devices.html">23 章 KDS デバイス端末ガイド</a> — タブレット選定</li><li><a href="./26-printer.html">26 章 プリンタ連携</a></li></ul><h2 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h2><ul><li><strong>2026-04-19 (S3 セキュリティ修正一式)</strong>: 19.S3 を新設。新規エラーコード一覧（INVALID_ITEM / INVALID_OPTION / INVALID_QUANTITY / ALREADY_PAID / AMOUNT_MISMATCH / STRIPE_MISMATCH / PAYMENT_NOT_CONFIRMED / INVALID_TOKEN / CONFLICT / CAPACITY_EXCEEDED / WEBHOOK_NOT_CONFIGURED）を追加。</li><li><strong>2026-04-19 (Batch-12)</strong>: 19.13 切り分けフローチャート / 19.14 5 軸切り分け (キャッシュ・セッション・GPS・Wi-Fi・DevTools) / 19.15 操作前チェックリスト / 19.16 実例 / 19.17 FAQ 15 件追加</li><li><strong>2026-04-19</strong>: 19.0「エラー番号の調べ方」を新設。<code>[Exxxx]</code> 形式表示・AI ヘルプデスク FAB への貼り付け・エラーカタログ（章 99）参照を案内。</li><li><strong>2026-04-18</strong>: フル粒度化</li></ul>`,171)])])}const u=a(o,[["render",n]]);export{b as __pageData,u as default};
